  "text": "func NewDerivedReader(wrapper wrapping.Wrapper, lenLimit int64, salt, info []byte) (*io.LimitedReader, error) {
n1: 	const op = "kms.NewDerivedReader"
n2: 	if wrapper == nil {
n3: 		return nil, errors.NewDeprecated(errors.InvalidParameter, op, "missing wrapper")
	}
n4: 	if lenLimit < 20 {
n5: 		return nil, errors.NewDeprecated(errors.InvalidParameter, op, "lenLimit must be >= 20")
	}
n6: 	var aeadWrapper *aead.Wrapper
n7: 	switch w := wrapper.(type) {
	case *multiwrapper.MultiWrapper:
		raw := w.WrapperForKeyID("__base__")
		var ok bool
		if aeadWrapper, ok = raw.(*aead.Wrapper); !ok {
			return nil, errors.NewDeprecated(errors.InvalidParameter, op, "unexpected wrapper type from multiwrapper base")
		}
	case *aead.Wrapper:
		if w.GetKeyBytes() == nil {
			return nil, errors.NewDeprecated(errors.InvalidParameter, op, "aead wrapper missing bytes")
		}
		aeadWrapper = w
	default:
		return nil, errors.NewDeprecated(errors.InvalidParameter, op, "unknown wrapper type")
	}
n8: 	reader := hkdf.New(sha256.New, aeadWrapper.GetKeyBytes(), salt, info)
n9: 	return &io.LimitedReader{
		R: reader,
		N: lenLimit,
	}, nil
}
